INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '343a51d4-b453-45b9-a275-e83e90c62ad8',
  '00000000-0000-0000-0000-000000000001',
  $escape$XGBoost Learning Rate Scheduling — There's No Adam Here$escape$,
  $escape$XGBoost isn't gradient descent — it's a second-order Newton booster. Each tree fits the negative first-order gradient and uses the Hessian to compute analytically optimal leaf weights. There's no SGD, Adam, or AdamW choice; the per-split update is already closed-form optimal.

The DL-equivalent concept is `eta` (`learning_rate`), which shrinks each tree's contribution to the ensemble. Unlike Adam's adaptive per-parameter rates, `eta` is global and static by default. For dynamic decay, use `xgb.callback.LearningRateScheduler`, which accepts a callable `f(round: int) -> float` and overrides `eta` each boosting round.

Exponential decay works well in practice: start at 0.3, decay by 0.95 per round. Early trees stay coarse and exploratory; later rounds fine-tune — analogous in effect to cosine annealing in DL. Always pair with `early_stopping_rounds`; an over-decayed `eta` lets the model keep boosting well past its optimal point with negligible score improvement.

One gotcha: the scheduler fully overrides the `eta` set in your `params` dict each round, so don't expect them to compose.$escape$,
  $escape$import xgboost as xgb

def exponential_decay(boosting_round: int) -> float:
    return 0.3 * (0.95 ** boosting_round)

dtrain = xgb.DMatrix(X_train, label=y_train)
dval   = xgb.DMatrix(X_val,   label=y_val)

params = {
    "objective": "reg:squarederror",
    "max_depth": 6,
    "eta": 0.3,          # overridden each round by the scheduler
}

model = xgb.train(
    params,
    dtrain,
    num_boost_round=300,
    evals=[(dval, "val")],
    early_stopping_rounds=20,
    callbacks=[xgb.callback.LearningRateScheduler(exponential_decay)],
)$escape$,
  $escape$python$escape$,
