INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b00e193b-c88e-4fa4-be05-502cabe55e04',
  '00000000-0000-0000-0000-000000000001',
  $escape$XGBoost Loss Functions — Choosing Built-ins vs. Rolling Your Own$escape$,
  $escape$XGBoost's `objective` parameter controls the loss function driving gradient boosting. For regression, `reg:squarederror` minimizes MSE but is sensitive to outliers — switch to `reg:pseudohubererror` for robustness. For classification, `binary:logistic` outputs probabilities; `binary:hinge` skips calibration and outputs hard labels. Multi-class? `multi:softmax` returns class indices while `multi:softprob` returns a probability matrix.

When built-ins fall short, XGBoost supports custom objectives via the `obj` parameter. Your function receives `(preds, dtrain)` and must return `(grad, hess)` — the first and second derivatives of your loss. Getting the Hessian wrong tanks convergence; it must be positive and ideally tight. A common trick: clamp the Hessian to a small epsilon (e.g. `1e-6`) to avoid division-by-zero instability.

Custom objectives disable `eval_metric` inference — you must explicitly pass a custom `feval` too. Use `xgb.train()` not the sklearn API for custom objectives; `XGBClassifier.fit()` doesn't support `obj` directly. Profile with `dtrain.get_label()` inside the objective to verify label shapes before training at scale.$escape$,
  $escape$import numpy as np
import xgboost as xgb

def log_cosh_obj(preds, dtrain):
    labels = dtrain.get_label()
    err = preds - labels
    grad = np.tanh(err)
    hess = 1.0 - grad ** 2  # sech^2(x), always in (0, 1]
    return grad, hess

def log_cosh_eval(preds, dtrain):
    labels = dtrain.get_label()
    loss = np.log(np.cosh(preds - labels))
    return "log_cosh", float(np.mean(loss))

dtrain = xgb.DMatrix(X_train, label=y_train)
params = {"max_depth": 4, "eta": 0.1, "seed": 42}
bst = xgb.train(params, dtrain, num_boost_round=100,
                obj=log_cosh_obj, feval=log_cosh_eval)$escape$,
  $escape$python$escape$,
