INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3785a052-a85d-4f19-a470-e50d8ef82117',
  '00000000-0000-0000-0000-000000000001',
  $escape$XGBoost GPU Acceleration — Switching to CUDA for 10x Faster Training$escape$,
  $escape$XGBoost's GPU backend uses CUDA to accelerate histogram construction and split finding — the two most expensive steps in gradient boosting. Switching is a single parameter change: set `device='cuda'` (XGBoost ≥2.0) or the legacy `tree_method='gpu_hist'`. Data doesn't need manual `.to('cuda')` calls — XGBoost handles DMatrix transfers internally when the device is set.

For mixed precision, XGBoost doesn't expose float16 training directly, but you can pass float16 numpy arrays or cuDF DataFrames into `DMatrix` and XGBoost will operate in float32 internally, reducing host-to-device transfer time. Pair this with `subsample` and `sampling_method='gradient_based'` (GPU-only) for further speedups — gradient-based sampling is only available on CUDA and outperforms uniform sampling on large datasets.

Use `device='cuda:1'` to pin to a specific GPU in multi-GPU machines. For distributed GPU training, switch to `device='cuda'` with Dask or Spark — XGBoost's collective backend coordinates across devices automatically. Always profile with `verbosity=2` to confirm GPU kernels are being dispatched.$escape$,
  $escape$import xgboost as xgb
import numpy as np

# float16 array — faster host-to-device transfer
X = np.random.rand(100_000, 50).astype(np.float16)
y = np.random.randint(0, 2, 100_000)

dtrain = xgb.DMatrix(X, label=y)

params = {
    "device": "cuda",           # XGBoost ≥2.0 unified device param
    "tree_method": "hist",      # hist + cuda = gpu_hist equivalent
    "sampling_method": "gradient_based",  # GPU-only sampler
    "subsample": 0.8,
    "max_depth": 6,
    "objective": "binary:logistic",
}

model = xgb.train(params, dtrain, num_boost_round=200)$escape$,
  $escape$python$escape$,
