INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0bad4cbf-062c-442b-84d1-2c31cb9ad43b',
  '00000000-0000-0000-0000-000000000001',
  $escape$XGBoost Model Evaluation — Metrics, Confusion Matrix, and Cross-Validation by Task Type$escape$,
  $escape$XGBoost exposes task-specific eval metrics via the `eval_metric` parameter. For binary classification, use `logloss` or `auc`; multiclass needs `mlogloss` or `merror`; regression uses `rmse`, `mae`, or `rmsle`. You can stack multiple metrics: `eval_metric=['auc', 'logloss']`. During training, pass `evals=[(dtrain, 'train'), (dval, 'val')]` to `xgb.train()` to track per-round metrics and catch overfitting early.

For confusion matrix and classification reports, XGBoost doesn't natively produce them — pipe `model.predict()` output into `sklearn.metrics`. Use `predict_proba()` (sklearn API) or threshold `model.predict()` raw scores manually for binary tasks.

Cross-validation is first-class via `xgb.cv()`, which returns a DataFrame of train/test metric means and standard deviations per boosting round. It respects `early_stopping_rounds`, making it the cleanest way to find optimal `n_estimators` without a manual holdout split. Always set `seed` for reproducibility.$escape$,
  $escape$import xgboost as xgb
from sklearn.metrics import confusion_matrix, classification_report

dtrain = xgb.DMatrix(X_train, label=y_train)
dval = xgb.DMatrix(X_val, label=y_val)

params = {
    'objective': 'binary:logistic',
    'eval_metric': ['auc', 'logloss'],
    'seed': 42
}

# Cross-validation to find optimal rounds
cv_results = xgb.cv(
    params, dtrain, num_boost_round=500,
    nfold=5, early_stopping_rounds=20, as_pandas=True
)
optimal_rounds = cv_results['test-logloss-mean'].idxmin()

# Final model with evals tracking
model = xgb.train(
    params, dtrain, num_boost_round=optimal_rounds,
    evals=[(dtrain, 'train'), (dval, 'val')]
)

preds = (model.predict(dval) > 0.5).astype(int)
print(confusion_matrix(y_val, preds))
print(classification_report(y_val, preds))$escape$,
  $escape$python$escape$,
